#include<bits/stdc++.h>
using namespace std;
int dp[301][301],a[301];
int main()
{
    int n;
    scanf("%d",&n);
    memset(dp,-1,sizeof(dp));
    int ans=INT_MIN;
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        dp[i][i]=a[i];
        ans=max(ans,a[i]);
    }
    for(int l=n;l>=1;l--)
    {
        for(int r=l+1;r<=n;r++)
        {
            for(int k=l;k<r;k++)
            {
                if(dp[l][k]==-1||dp[k+1][r]==-1||dp[l][k]!=dp[k+1][r])
                {
                    continue;
                }
                dp[l][r]=max(dp[l][r],dp[l][k]+1);
            }
            ans=max(ans,dp[l][r]);
        }
    }
    printf("%d",ans);
    return 0;
}
